var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무사 귀환을 축하드립니다.","JPN":"無事帰還できてよかったです。","ENG":"Congratulations on your safe return.","TWN":"恭喜安全回歸。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마지막 그림자형 침식체를 놓친 건 아쉽지만 이것만으로도 큰 성과라고 할 수 있겠죠.","JPN":"最後のシャドウ型侵食体を取り逃がしたのは残念ですが、これだけでも大いなる成果と言えるでしょう。","ENG":"Although it's regrettable that we lost the final Shadow-type C.O., I think we've achieved considerable success.","TWN":"雖然最後讓暗影型侵蝕體溜掉了有些可惜，但仍算是大獲成功了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"3종 침식체 한 마리도 상대를 못해서 쩔쩔매던 게 엊그제 같은데 말입니다.","JPN":"第3種侵食体1匹相手に手こずっていたのが昨日のことのようですが。","ENG":"I mean, it wasn't so long ago that we couldn't even face off a single Category 3.","TWN":"以前可是連一隻3類侵蝕體都對付不了呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실히 스승님이 돌아오신 후로 회사의 사정이 점점 좋아지고 있는 것 같아 흐뭇하군요.","JPN":"師匠が戻られてから、会社の業績も徐々に安定してきて微笑ましいですね。","ENG":"The company seems to be getting back on its feet ever since the Master's return.","TWN":"自從老師回來之後，公司的情況越來越好了，我真的很高興。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모두들 수고하셨습니다.","JPN":"みなさん、お疲れ様でした。","ENG":"Good work, everyone.","TWN":"各位辛苦了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 정도야 별거 아니지! 다음에도 기대하라고!","JPN":"この程度の仕事なら簡単だ！　次も期待していいぞ！","ENG":"Aw, that was a piece of cake! You can count on me again!","TWN":"這不算什麼啦！期待我下一次的表現吧！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그래. 앞으로도 미끼 역할은 쭉~ 너니까 기대할게.","JPN":"そうね。これからもエサ役はずーっとあんただからそこは期待する。","ENG":"Yeah. I'll be counting on you to be the bait again.","TWN":"好，那以後你就專門負責當誘餌，我會期待你的表現的。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 이 자식아? 지금 뭐라고 했어!","JPN":"ああん？　お前、もう一回言ってみろ！","ENG":"What? You jerk! What did you just say?","TWN":"什麼？你這傢伙？你剛說什麼？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"네 입으로 다음에도 기대하라며?","JPN":"自分の口から次も期待してって言ったでしょ？","ENG":"You're the one who said we could count on you.","TWN":"不是你自己說讓我期待的嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"왜, 기대하지 마?","JPN":"期待しない方がいいの？","ENG":"Should we not count on you then?","TWN":"怎麼，不用期待了？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아, 아니 그건 아니고, 기대하라는 건 맞는데......","JPN":"いや、それは違うけど。期待していいけど……","ENG":"Y-yes, but that's not what I meant...","TWN":"不、不是，當然要期待……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"왜 이렇게 기분이 찝찝하지?","JPN":"なんだかスッキリしないな。","ENG":"Why do I feel like I've been duped?","TWN":"不過，怎麼感覺怪怪的？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장...... 계좌 확인해 봤어?","JPN":"た、隊長……残高は確認した？","ENG":"C-Cap... Did you check the bank account?","TWN":"隊、隊長……你查看帳戶了嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"정식 라이선스 소대가 돼서 그런지 작전 수당도 늘어났나 봐.","JPN":"正式ライセンス小隊になったおかげで、作戦手当も増えたみたい。","ENG":"They must have given us a raise for our mission bonus, now that we're an officially licensed squad.","TWN":"不知道是不是因為成為正式小隊的關係，作戰補貼好像變多了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후훗, 이번엔 관리국의 긴급 지원 요청까지 해결했잖아?","JPN":"ふふ、今回は管理局の緊急応援要請まで解決したからね。","ENG":"Hah hah, we even took care of the Administration's request for emergency support this time.","TWN":"嘻嘻，這次還處理了管理局的緊急支援請求。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아마 3종 침식체 격파에 따른 추가 지원금도 같이 들어왔을 거야.","JPN":"たぶん第3種侵食体撃破による追加補助金も振り込まれたと思うわ。","ENG":"I bet we got an extra bonus for taking down the Category 3.","TWN":"應該還包括了消滅3類侵蝕體的額外支援金。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"응. 이 정도면 당분간 생활비 걱정은 안 해도 될 것 같아.","JPN":"うん。これくらいあれば、しばらく生活費の心配はないかな。","ENG":"Great. We shouldn't have to worry about paying the bills for a while now.","TWN":"嗯。有了這些錢，暫時不用擔心生活費了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"장보러 가자! 오늘은 특식이야!","JPN":"買い出しに行こう！　今日はフルコースを振る舞うね！","ENG":"Let's go grocery shopping! I'm making you something special today!","TWN":"我們去買東西吧！今天吃大餐！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};